// modules/teams/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'teams',
  description: 'Handles team creation, management, and membership utilities.',

  dependencies: { modules: [] },

  exposes: {
    routes: [
      { method: 'POST', path: '/teams/create', auth: true },
    ],
    functions: ['createTeam'],
    types: ['Team', 'TeamMember', 'TeamError'],
  },

  sideEffects: [
    'writes to: teams table',
    'writes to: team_members table',
  ],

  invariants: [
    'A team must always have at least one owner',
    'Owner of a team must be a member of the team',
  ],
});

// modules/teams/lib/types.ts
export interface Team {
  id: number;
  name: string;
  description?: string;
}

export interface TeamMember {
  id: number;
  teamId: number;
  userId: number;
  role: 'owner' | 'member';
}

export interface TeamError {
  code: string;
  message: string;
}

// modules/teams/lib/db.ts
import { query } from '../db';

export async function createTeam(team: Partial<Team>): Promise<Result<Team, TeamError>> {
  try {
    const result = await query(
      'INSERT INTO teams (name, description) VALUES ($1, $2) RETURNING *',
      [team.name, team.description]
    );
    return ok(result.rows[0]);
  } catch (error) {
    return err({ code: 'TEAM_CREATE_FAILED', message: error.message });
  }
}

// modules/teams/lib/auth.ts
import { requireUser } from '../auth';

export async function createTeamHandler(req: Request, res: Response): Promise<void> {
  const user = await requireUser(req);
  const teamData = parseBody<Team>(req.body);

  const result = await createTeam({ ...teamData, owner_id: user.id });

  if (result.isOk()) {
    emit('team.created', { teamId: result.value.id });
    res.status(201).json(result.value);
  } else {
    res.status(400).json(result.error);
  }
}

// modules/teams/routes.ts
import express from 'express';
import { createTeamHandler } from '../lib/auth';

const router = express.Router();

router.post('/teams/create', authMiddleware, createTeamHandler);

export default router;

// modules/teams/lib/validate.ts
import { z } from 'zod';

export const teamSchema = z.object({
  name: z.string().min(1),
  description: z.string().optional(),
});

export function parseBody<T>(body: any): T {
  return teamSchema.parse(body);
}

// modules/teams/lib/result.ts
import { Result, ok, err } from '../result';

export type TeamResult = Result<Team, TeamError>;

// modules/teams/lib/db.ts
import { query } from '../db';

export async function createTeam(team: Partial<Team>): Promise<Result<Team, TeamError>> {
  try {
    const result = await query(
      'INSERT INTO teams (name, description) VALUES ($1, $2) RETURNING *',
      [team.name, team.description]
    );
    return ok(result.rows[0]);
  } catch (error) {
    return err({ code: 'TEAM_CREATE_FAILED', message: error.message });
  }
}

// modules/teams/lib/auth.ts
import { requireUser } from '../auth';

export async function createTeamHandler(req: Request, res: Response): Promise<void> {
  const user = await requireUser(req);
  const teamData = parseBody<Team>(req.body);

  const result = await createTeam({ ...teamData, owner_id: user.id });

  if (result.isOk()) {
    emit('team.created', { teamId: result.value.id });
    res.status(201).json(result.value);
  } else {
    res.status(400).json(result.error);
  }
}

// modules/teams/routes.ts
import express from 'express';
import { createTeamHandler } from '../lib/auth';

const router = express.Router();

router.post('/teams/create', authMiddleware, createTeamHandler);

export default router;

// modules/teams/lib/validate.ts
import { z } from 'zod';

export const teamSchema = z.object({
  name: z.string().min(1),
  description: z.string().optional(),
});

export function parseBody<T>(body: any): T {
  return teamSchema.parse(body);
}

